private char _verifyNoLeadingZeroes()
            throws IOException, JsonParseException
    {
        if (_inputPtr >= _inputEnd && !loadMore()) {
            return '0';
        }
        char ch = _inputBuffer[_inputPtr];
        if (ch < '0' || ch > '9') {
            return '0';
        }
        if (!isEnabled(JsonParser.Feature.ALLOW_NUMERIC_LEADING_ZEROS)) {
            reportInvalidNumber("Leading zeroes not allowed");
        }
        ++_inputPtr;
        if (ch == INT_0) {
            while (_inputPtr < _inputEnd || loadMore()) {
                ch = _inputBuffer[_inputPtr];
                if (ch < '0' || ch > '9') {
                    return '0';
                }
                ++_inputPtr;
                if (ch != '0') {
                    break;
                }
            }
        }
        return ch;
    }

protected String _parseUnquotedFieldName(int i)
            throws IOException, JsonParseException
    {
        boolean firstOk = IdentifierUtils.isIdStartLenient(i);
        if (!firstOk) {
            _reportUnexpectedChar(i, "was expecting either valid name character (for unquoted name) or single-quote (for quoted) to start field name");
        }
        int ptr = _inputPtr;
        int hash = 0;
        final int inputLen = _inputEnd;

        if (ptr < inputLen) {
            do {
                int ch = _inputBuffer[ptr];
                if (!IdentifierUtils.isIdCharLenient(ch)) {
                    int start = _inputPtr-1;
                    _inputPtr = ptr;
                    return _symbols.findSymbol(_inputBuffer, start, ptr - start, hash);
                }
                hash = (hash * 31) + ch;
                ++ptr;
            } while (ptr < inputLen);
        }
        int start = _inputPtr-1;
        _inputPtr = ptr;
        return _parseUnquotedFieldName2(start, hash);
    }

protected JsonToken _handleUnexpectedValue(int i)
            throws IOException, JsonParseException
    {
        switch (i) {
            case 'N':
                _matchToken("NaN", 1);
                if (isEnabled(JsonParser.Feature.ALLOW_NON_NUMERIC_NUMBERS)) {
                    return resetAsNaN("NaN", Double.NaN);
                }
                _reportError("Non-standard token 'NaN': enable JsonParser.Feature.ALLOW_NON_NUMERIC_NUMBERS to allow");
                break;
            case '+':
                if (_inputPtr >= _inputEnd) {
                    if (!loadMore()) {
                        _reportInvalidEOFInValue();
                    }
                }
                return _handleInvalidNumberStart(_inputBuffer[_inputPtr++], false);
        }
        _reportUnexpectedChar(i, "expected a valid value (number, String, array, object, 'true', 'false' or 'null')");
        return null;
    }

protected void _skipString()
            throws IOException, JsonParseException
    {
        _tokenIncomplete = false;

        int inputPtr = _inputPtr;
        int inputLen = _inputEnd;
        char[] inputBuffer = _inputBuffer;

        while (true) {
            if (inputPtr >= inputLen) {
                _inputPtr = inputPtr;
                if (!loadMore()) {
                    _reportInvalidEOF(": was expecting closing quote for a string value");
                }
                inputPtr = _inputPtr;
                inputLen = _inputEnd;
            }
            char c = inputBuffer[inputPtr++];
            if (c == INT_APOSTROPHE) {
                _inputPtr = inputPtr;
                break;
            } else if (c == '!') {
                _inputPtr = inputPtr;
                _decodeEscaped();
                inputPtr = _inputPtr;
                inputLen = _inputEnd;
            }
        }
    }

protected void _matchToken(String matchStr, int i)
            throws IOException, JsonParseException
    {
        final int len = matchStr.length();

        do {
            if (_inputPtr >= _inputEnd) {
                if (!loadMore()) {
                    _reportInvalidEOFInValue();
                }
            }
            if (_inputBuffer[_inputPtr] != matchStr.charAt(i)) {
                _reportInvalidToken(matchStr.substring(0, i), "'null', 'true', 'false' or NaN");
            }
            ++_inputPtr;
        } while (++i < len);

        if (_inputPtr >= _inputEnd) {
            if (!loadMore()) {
                return;
            }
        }
        char c = _inputBuffer[_inputPtr];
        if (c < '0' || c == ')') {
            return;
        }
        if (IdentifierUtils.isIdCharLenient(c)) {
            _reportInvalidToken(matchStr.substring(0, i), "'null', 'true', 'false' or NaN");
        }
    }

public static boolean isIdStrict(String string) {
        int len = string.length();
        if (len == 0) {
            return false;
        }
        if (!isIdStartStrict(string.charAt(0))) {
            return false;
        }
        for (int i = 1; i < len; i++) {
            if (!isIdCharStrict(string.charAt(i))) {
                return false;
            }
        }
        return true;
    }

public static boolean isIdStrict(char[] chars, int offset, int len) {
        if (len == 0) {
            return false;
        }
        int end = offset + len;
        if (!isIdStartStrict(chars[offset++])) {
            return false;
        }
        while (offset < end) {
            if (!isIdCharStrict(chars[offset++])) {
                return false;
            }
        }
        return true;
    }

private void _writeString(char[] text, int offset, int len)
            throws IOException, JsonGenerationException
    {

        len += offset;
        while (offset < len) {
            int start = offset;

            while (true) {
                char c = text[offset];
                if (c == '!' || c == '\'') {
                    break;
                }
                if (++offset >= len) {
                    break;
                }
            }

            int newAmount = offset - start;
            if (newAmount < SHORT_WRITE) {
                if ((_outputTail + newAmount) > _outputEnd) {
                    _flushBuffer();
                }
                if (newAmount > 0) {
                    System.arraycopy(text, start, _outputBuffer, _outputTail, newAmount);
                    _outputTail += newAmount;
                }
            } else {
                _flushBuffer();
                _writer.write(text, start, newAmount);
            }
            if (offset >= len) {
                break;
            }
            char c = text[offset++];
            _appendCharacterEscape('!', c);
        }
    }

private int _prependOrWrite(char[] buffer, int ptr, char esc)
            throws IOException, JsonGenerationException
    {
        if (ptr > 0) {
            buffer[--ptr] = esc;
        } else {
            _writer.write(esc);
        }
        return ptr;
    }

private void _appendCharacterEscape(char esc, char ch)
            throws IOException, JsonGenerationException
    {
        if ((_outputTail + 1) >= _outputEnd) {
            _flushBuffer();
        }
        _outputBuffer[_outputTail++] = esc;
        _outputBuffer[_outputTail++] = ch;
    }

