static String getMiddleNameForPrefixingAsAccessorMutatorJavaBeansSpecCompliance(String fieldName) {
        if (fieldName.length() > 1 && Character.isUpperCase(fieldName.charAt(1))) {
            return fieldName;
        }
        return fieldName.substring(0, 1).toUpperCase() + fieldName.substring(1);
    }

private boolean exists(JClassType type, JField field, String fieldName, boolean isSetter) {
        if (field instanceof DummyJField) {
            return true;
        }

        JType[] args;
        if (isSetter) {
            args = new JType[] { field.getType() };
        } else {
            args = new JType[] {};
        }
        JMethod m = type.findMethod(fieldName, args);
        if (null != m) {
            if (isIgnored(m)) {
                return false;
            }
            if (isSetter) {
                return true;
            }
            JClassType returnType = m.getReturnType().isClassOrInterface();
            JClassType fieldType = field.getType().isClassOrInterface();
            if (returnType == null || fieldType == null) {
                return m.getReturnType().equals(field.getType());
            }
            return returnType.isAssignableFrom(fieldType);
        }
        try {
            JType objectType = find(Object.class, getLogger(), context);
            JClassType superType = type.getSuperclass();
            if (!objectType.equals(superType)) {
                return exists(superType, field, fieldName, isSetter);
            }
        } catch (UnableToCompleteException e) {
        }
        return false;
    }

public static List<AnnotationResolver> getAnnotationResolvers(GeneratorContext context,
                                                                  TreeLogger logger) {

        if (null == _annotationResolversRequested) {
            try {
                for (String className : context.getPropertyOracle()
                    .getConfigurationProperty("org.fusesource.restygwt.annotationresolver").getValues()) {
                    logger.log(TreeLogger.INFO, "classname to resolve: " + className);
                    Class<?> clazz;

                    try {
                        clazz = Class.forName(className);
                    } catch (ClassNotFoundException e) {
                        throw new RuntimeException("could not resolve class " + className + " " + e.getMessage());
                    }

                    if (null != clazz) {
                        try {
                            logger.log(TreeLogger.INFO, "add annotationresolver: " + clazz.getName());
                            addAnnotationResolver((AnnotationResolver) clazz.newInstance());
                        } catch (InstantiationException e) {
                            throw new RuntimeException("could not instanciate class " + className + " " + e.getMessage());
                        } catch (IllegalAccessException e) {
                            throw new RuntimeException("could not access class " + className + " " + e.getMessage());
                        }
                    } else {
                        throw new RuntimeException("could not create instance for classname " + className);
                    }
                }
            } catch (BadPropertyValueException ignored) {

                logger.log(TreeLogger.DEBUG, "no additional annotationresolvers found");
            }
        }

        List<AnnotationResolver> ret = new ArrayList<AnnotationResolver>();

        ret.addAll(annotationResolvers);
        return _annotationResolversRequested = ret;
    }

