private Response process(
            MultivaluedMap<String, String> parameters, String clientId,
            String clientSecret, String[] clientCertificatePath)
    {
        Property[] properties = mSpi.getProperties();

        String clientCertificate = null;
        if (clientCertificatePath != null && clientCertificatePath.length > 0)
        {
            clientCertificate = clientCertificatePath[0];

            if (clientCertificatePath.length > 1)
            {
                clientCertificatePath = Arrays.copyOfRange(
                        clientCertificatePath, 1, clientCertificatePath.length);
            }
        }

        TokenResponse response = getApiCaller().callToken(
                parameters, clientId, clientSecret, properties,
                clientCertificate, clientCertificatePath);

        Action action = response.getAction();

        String content = response.getResponseContent();

        switch (action)
        {
            case INVALID_CLIENT:
                return ResponseUtil.unauthorized(content, CHALLENGE);

            case INTERNAL_SERVER_ERROR:
                return ResponseUtil.internalServerError(content);

            case BAD_REQUEST:
                return ResponseUtil.badRequest(content);

            case PASSWORD:
                return handlePassword(response);

            case OK:
                return ResponseUtil.ok(content);

            default:
                throw getApiCaller().unknownAction("/api/auth/token", action);
        }
    }

private Response handlePassword(TokenResponse response)
    {
        String username = response.getUsername();
        String password = response.getPassword();

        String subject = mSpi.authenticateUser(username, password);

        Property[] properties = mSpi.getProperties();

        String ticket = response.getTicket();

        if (subject != null)
        {
            return getApiCaller().tokenIssue(ticket, subject, properties);
        }
        else
        {
            throw getApiCaller().tokenFail(ticket, Reason.INVALID_RESOURCE_OWNER_CREDENTIALS);
        }
    }

public Response handle(String ticket, String[] claimNames, String[] claimLocales) throws WebApplicationException
    {
        try
        {
            return process(ticket, claimNames, claimLocales);
        }
        catch (WebApplicationException e)
        {
            throw e;
        }
        catch (Throwable t)
        {
            throw unexpected("Unexpected error in AuthorizationDecisionHandler", t);
        }
    }

private Response process(String ticket, String[] claimNames, String[] claimLocales)
    {
        if (mSpi.isClientAuthorized() == false)
        {
            return fail(ticket, Reason.DENIED);
        }

        String subject = mSpi.getUserSubject();

        if (subject == null || subject.length() == 0)
        {
            return fail(ticket, Reason.NOT_AUTHENTICATED);
        }

        long authTime = mSpi.getUserAuthenticatedAt();

        String acr = mSpi.getAcr();

        Map<String, Object> claims = collectClaims(subject, claimNames, claimLocales);

        Property[] properties = mSpi.getProperties();

        String[] scopes = mSpi.getScopes();

        return authorize(ticket, subject, authTime, acr, claims, properties, scopes);
    }

private Map<String, Object> collectClaims(String subject, String[] claimNames, String[] claimLocales)
    {
        if (claimNames == null || claimNames.length == 0)
        {
            return null;
        }

        claimLocales = normalizeClaimLocales(claimLocales);

        Map<String, Object> claims = new HashMap<String, Object>();

        for (String claimName : claimNames)
        {
            if (claimName == null || claimName.length() == 0)
            {
                continue;
            }

            String[] elements = claimName.split("#", 2);
            String name = elements[0];
            String tag  = (elements.length == 2) ? elements[1] : null;

            if (name == null || name.length() == 0)
            {
                continue;
            }

            Object value = getClaim(name, tag, claimLocales);

            if (value == null)
            {
                continue;
            }

            if (tag == null)
            {
                claimName = name;
            }

            claims.put(claimName, value);
        }

        if (claims.size() == 0)
        {
            return null;
        }

        return claims;
    }

