		if (registeredAsStatic == staticMode) {
			try {
				EmbeddedServerRunner serverAdapter = findEmbeddedServerAdapterInStore(context);
				serverAdapter.afterAll();
			}
			finally {
				removeEmbeddedServerAdapterFromStore(context);
			}
		}
	}

