@Override
    public void configure(final String name, final Object value, final Logger logger) {
        if (ROOT.equals(name)) {
            if (value instanceof String) {
                root = (String) value;
                logger.logInfo("Configured root DN for directory server: " + root);
            }
        } else if (OBJECT_CLASSES.equals(name)) {
            if (value instanceof String[]) {
                objectClasses = (String[]) value;
                logger.logInfo("Configured object classes for root DN: " + objectClasses);
            }
        } else if (AUTH_DN.equals(name)) {
            if (value instanceof String) {
                authDn = (String) value;
                logger.logInfo("Configured admin identity for directory server: " + authDn);
            }
        } else if (PASSWD.equals(name)) {
            if (value instanceof String) {
                passwd = (String) value;
                logger.logInfo("Configured admin credentials for directory server: " + passwd);
            }
        } else if (WORK_DIR.equals(name)) {
            if (value instanceof File) {
                workingDirectory = (File) value;
                logger.logInfo("Configured working directory for directory server: " + workingDirectory);
            }
        } else if (LDIF_FILE.equals(name)) {
            if (value instanceof File) {
                ldifFile = (File) value;
                logger.logInfo("Configured LDIF seed data source for directory server: " + ldifFile);
            }
        } else if (LDAP_PORT.equals(name)) {
            if (value instanceof Integer) {
                serverPort = (Integer) value;
                logger.logInfo("Configured TCP port for directory server: " + serverPort);
            }
        }
    }

@Override
    public void start(final Logger logger) {
        try {
            logger.logInfo("Starting UnboundID server");
            final InMemoryListenerConfig listenerConfig = InMemoryListenerConfig.createLDAPConfig("default", getServerPort());
            final InMemoryDirectoryServerConfig config = new InMemoryDirectoryServerConfig(new DN(getRoot()));
            config.setListenerConfigs(listenerConfig);
            if (getAuthDn() != null) {
                config.addAdditionalBindCredentials(getAuthDn(), getPasswd());
            }
            server = new InMemoryDirectoryServer(config);
            String[] objectClasses = getObjectClasses();
            if (objectClasses == null) {
                objectClasses = DEFAULT_ROOT_OBJECT_CLASSES;
            }
            server.add(new Entry(getRoot(), new Attribute("objectclass", objectClasses)));
            if (getLdifFile() != null) {
                final InputStream in = new FileInputStream(getLdifFile());
                try {
                    final LDIFReader reader = new LDIFReader(in);
                    server.importFromLDIF(false, reader);
                } finally {
                    in.close();
                }
            }
            server.startListening();
            logger.logInfo("Started UnboundID server");
        } catch (final LDAPException e) {
            e.printStackTrace();
            logger.logError("Could not launch embedded UnboundID directory server", e);
        } catch (final IOException e) {
            e.printStackTrace();
            logger.logError("Could not launch embedded UnboundID directory server", e);
        }
