protected void sendMetric(MetricBuilder metricBuilder) throws ReportingException {
    try {
      HttpClient client = new HttpClient("http:
      Response response = client.pushMetrics(metricBuilder);

      if (response.getStatusCode() / 100 != 2) {
        LOGGER.error("Kairos DB reported error. Status code: " + response.getStatusCode());
        LOGGER.error("Error message: " + response.getErrors());
        throw new ReportingException();
      } else {
        LOGGER.debug("Kairos DB returned OK. Status code: " + response.getStatusCode());
      }
      client.shutdown();
    } catch (MalformedURLException | URISyntaxException e) {
      throw new ConfigurationException(e);
    } catch (IOException e) {
      LOGGER.error("Could not request KairosDB.", e);
      throw new ReportingException(e);
    }
  }

@Override
  public void report(Metric metric) throws ReportingException {

    KairosMetricConverter kairosMetricConverter = new KairosMetricConverter();
    try {
      kairosMetricConverter.add(metric);
    } catch (KairosMetricConversionException e) {
      throw new ReportingException(e);
    }
    this.sendMetric(kairosMetricConverter.convert());
  }

public static GeometryTypeInfo readGeometryType(ByteReader reader) {

		byte byteOrderValue = reader.readByte();
		ByteOrder byteOrder = byteOrderValue == 0 ? ByteOrder.BIG_ENDIAN
				: ByteOrder.LITTLE_ENDIAN;
		reader.setByteOrder(byteOrder);

		long unsignedGeometryTypeCode = reader.readUnsignedInt();

		boolean hasZ = false;
		if (unsignedGeometryTypeCode > WKB25D) {
			hasZ = true;
			unsignedGeometryTypeCode -= WKB25D;
		}

		int geometryTypeCode = (int) unsignedGeometryTypeCode;

		GeometryType geometryType = GeometryCodes
				.getGeometryType(geometryTypeCode);

		if (!hasZ) {
			hasZ = GeometryCodes.hasZ(geometryTypeCode);
		}
		boolean hasM = GeometryCodes.hasM(geometryTypeCode);

		GeometryTypeInfo geometryInfo = new GeometryTypeInfo(geometryTypeCode,
				geometryType, hasZ, hasM);

		return geometryInfo;
	}

public static Point readPoint(ByteReader reader, boolean hasZ, boolean hasM) {

		double x = reader.readDouble();
		double y = reader.readDouble();

		Point point = new Point(hasZ, hasM, x, y);

		if (hasZ) {
			double z = reader.readDouble();
			point.setZ(z);
		}

		if (hasM) {
			double m = reader.readDouble();
			point.setM(m);
		}

		return point;
	}

public static LineString readLineString(ByteReader reader, boolean hasZ,
			boolean hasM) {

		LineString lineString = new LineString(hasZ, hasM);

		int numPoints = reader.readInt();

		for (int i = 0; i < numPoints; i++) {
			Point point = readPoint(reader, hasZ, hasM);
			lineString.addPoint(point);

		}

		return lineString;
	}

