        } else {
            return false;
        }
    }

private void onOperationFinished(@NonNull final OperationDelivery<?> operationResult) {
        logd("onOperationFinished " + operationResult);
        switch (mState) {
            case PAUSED:
                storeResult(operationResult);
                break;
            case RESUMED:
                deliverResult(operationResult);
                break;
            default:
                throw new IllegalStateException("Unknown state: " + mState);
        }
    }

private void storeResult(@NonNull final OperationDelivery<?> operationDelivery) {
        logd("store delivery " + operationDelivery);
        mStoredResults.add(new SoftReference<OperationDelivery<?>>(operationDelivery));
    }

private void deliverResult(@NonNull final OperationDelivery<?> operationDelivery) {
        logd("deliver delivery " + operationDelivery);
        switch (operationDelivery.getDeliveryMode()) {
            case NORMAL:
                deliverResult(operationDelivery.getResult(), Chronos.OWN_CALLBACK_METHOD_NAME,
                        true);
                break;
            case BROADCAST:
                deliverResult(operationDelivery.getResult(), Chronos.BROADCAST_CALLBACK_METHOD_NAME,
                        false);
                break;
            default:
                break;
        }
    }

@SuppressWarnings("TryWithIdenticalCatches")
    private void deliverResult(@NonNull final ChronosOperationResult<?> operationResult,
            @NonNull final String methodName, final boolean warnIfNoCallback) {
        final Class listenerClass = mServiceListener.getClass();
        final Method[] listenerMethods = listenerClass.getMethods();

        Method callbackMethod = null;

        final Class resultClass = operationResult.getClass();
        for (Method method : listenerMethods) {
            if (isCallback(method, resultClass, methodName)) {
                callbackMethod = method;
                try {
                    callbackMethod.invoke(mServiceListener, operationResult);
                } catch (IllegalAccessException e) {
                    Log.w(LOG_TAG, Log.getStackTraceString(e));
                } catch (InvocationTargetException e) {
                    Log.w(LOG_TAG, Log.getStackTraceString(e));
                }
            }
        }

        if (warnIfNoCallback && callbackMethod == null) {
            Log.w(LOG_TAG,
                    "Operation result (id=" + operationResult.getId() + "; class=" + operationResult
                            .getClass().getName() + ") was obtained, but there is no method in "
                            + mServiceListener + " to get it"
            );
            Log.w(LOG_TAG, "Method should look like");
            Log.w(LOG_TAG,
                    "public void " + methodName + "(" + resultClass.getName()
                            + " result) {}"
            );
        }
    }

private void logd(@NonNull final String message) {
        if (LOG_ENABLED) {
            Log.d(LOG_TAG, this.toString() + " " + message);
        }
    }

private synchronized boolean cancel(final int id, final boolean mayInterrupt,
            final boolean removeOperation) {
        final RunningOperation runningOperation = mRunningOperations.get(id);
        if (runningOperation != null) {
            if (removeOperation) {
                mRunningOperations.remove(id);
            }
            mCancelledOperations.add(id);
            return runningOperation.cancel(mayInterrupt);
        } else {
            return false;
        }
    }

synchronized final void operationStarted(final int id, @NonNull final ChronosOperation<?> operation,
            @NonNull final Future<?> future
    ) {
        mRunningOperations.put(id, new RunningOperation(operation, future));
    }

synchronized final void cancelAll(final boolean mayInterrupt) {
        for (final Integer key : mRunningOperations.keySet()) {
            cancel(key, mayInterrupt, false);
        }

        mRunningOperations.clear();
    }

@Contract(pure = true)
    synchronized final boolean isOperationCancelled(final int id) {
        return mCancelledOperations.contains(Integer.valueOf(id));
    }

private static <Output> void silentRun(@NonNull final ChronosOperation<Output> operation,
            @NonNull final ChronosOperationResult<Output> operationResult) {
        try {
            final Output output = operation.run();
            operationResult.setOutput(output);
        } catch (Exception e) {
            operationResult.setException(e);
        }
    }

@NonNull
    @Contract(pure = true)
    private <Output> ChronosOperationResult<Output> createEmptyResult(
            @NonNull final ChronosOperation<Output> operation, final boolean broadcastResult) {
        final ChronosOperationResult<Output> operationResult;
        final Class<? extends ChronosOperationResult<Output>> resultClass = operation
                .getResultClass();
        try {
            operationResult = resultClass.newInstance();
        } catch (InstantiationException e) {
            throw new RuntimeException("Can't create a new instance of " + resultClass.getName());
        } catch (IllegalAccessException e) {
            throw new RuntimeException(resultClass.getName() + " constructor is not accessible");
        }
        operationResult.setId(mLastOperationId.incrementAndGet());
        operationResult.setOperation(operation);
        operationResult.setBroadcast(broadcastResult);

        return operationResult;
    }

final <Output> int runAsync(@NonNull final ChronosOperation<Output> operation,
            final boolean broadcastResult) {
        final ChronosOperationResult<Output> result = createEmptyResult(operation, broadcastResult);
        final int id = result.getId();

        synchronized (ChronosService.this) {
            RunningOperationStorage.getInstance().operationStarted(id, operation,
                    mExecutorService.submit(new Runnable() {
                        @Override
                        public void run() {
                            silentRun(operation, result);
                            mEventBus.post(result);
                            synchronized (ChronosService.this) {
                                RunningOperationStorage.getInstance().operationFinished(id);
                            }
                        }
                    }));
        }
        return id;
    }

@NonNull
    final <Output> ChronosOperationResult<Output> runSync(
            @NonNull final ChronosOperation<Output> operation, final boolean broadcastResult) {
        final ChronosOperationResult<Output> result = createEmptyResult(operation, broadcastResult);

        silentRun(operation, result);
        mEventBus.post(result);

        return result;
    }

