            long now = System.currentTimeMillis();
            if (lastAccessTimestampMs + LAST_ACCESS_THRESHOLD_MS < now) {
                lastAccessTimestampMs = now;
                return true;
            }
        }
        return false;
    }

protected void refreshTTL(String key, CacheEntry ce) {
        final String KEY = calcCacheKey(key);
        final long TTL = ce.getExpireAfterAccess();
        try (ShardedJedis jedis = getJedis()) {
            if (TTL > 0) {
                if (keyMode == KeyMode.HASH) {
                    jedis.expire(getName(), (int) TTL);
                } else {
                    jedis.expire(SafeEncoder.encode(KEY), (int) TTL);
                }
            }
        } catch (Exception e) {
            throw e instanceof CacheException ? (CacheException) e : new CacheException(e);
        }
    }

public static Object tryClone(Object toBeCloned) {
        if (toBeCloned == null) {
            return null;
        }
        Object clonedObj = null;
        if (toBeCloned instanceof Cloneable) {
            try {
                Method method = Object.class.getDeclaredMethod("clone");
                method.setAccessible(true);
                clonedObj = method.invoke(toBeCloned);
            } catch (Exception e) {
                if (e instanceof CloneNotSupportedException) {
                    clonedObj = toBeCloned;
                } else {
                    throw e instanceof RuntimeException ? (RuntimeException) e
                            : new RuntimeException(e);
                }
            }
        } else {
            clonedObj = toBeCloned;
        }
        return clonedObj;
    }

public AbstractCache init() {

        long oldCapacity = this.capacity;
        try {
            String entry = getCacheProperty(CACHE_PROP_CAPACITY);
            if (entry != null) {
                this.capacity = Long.parseLong(entry);
            }
        } catch (Exception e) {
            this.capacity = oldCapacity;
            LOGGER.warn(e.getMessage(), e);
        }
        if (capacity < -1) {
            setCapacity(-1);
        }


        long oldExpireAfterAccess = this.expireAfterAccess;
        try {
            String entry = getCacheProperty(CACHE_PROP_EXPIRE_AFTER_ACCESS);
            if (entry != null) {
                this.expireAfterAccess = Long.parseLong(entry);
            }
        } catch (Exception e) {
            this.expireAfterAccess = oldExpireAfterAccess;
            LOGGER.warn(e.getMessage(), e);
        }
        if (expireAfterAccess < -1) {
            setExpireAfterAccess(-1);
        }


        long oldExpireAfterWrite = this.expireAfterWrite;
        try {
            String entry = getCacheProperty(CACHE_PROP_EXPIRE_AFTER_WRITE);
            if (entry != null) {
                this.expireAfterWrite = Long.parseLong(entry);
            }
        } catch (Exception e) {
            this.expireAfterWrite = oldExpireAfterWrite;
            LOGGER.warn(e.getMessage(), e);
        }
        if (expireAfterWrite < -1) {
            setExpireAfterWrite(-1);
        }

        return this;
    }

