public InvocationResponse dispatchInvocation(InvocationRequest request) {
		String appName = request.getAppName();
		String serviceName = request.getServiceName();
		String componentName = mServiceTable.getComponentForService(appName, serviceName);

		if (componentName == null) {
			return InvocationResponse.error("Application " + appName + " doesn't have a service named " + serviceName);
		}

		AppServiceProxy proxy = mCommunicationAgent.getProxy(componentName);
		if (proxy == null) {
			return InvocationResponse.error("Cannot bind to service");
		}

		try {
			return proxy.executeService(request);
		} catch (Throwable t) {
			Log.e("ServiceRegistry", "Error dispatching invocation: ", t);
			return InvocationResponse.error("Internal error: " + t.getMessage());
		}
	}

public <T> void unregisterService(Class<? super T> serviceInterface) {
		Utils.notNull(serviceInterface, "serviceInterface must not be null");
		ServiceValidator.validateInterface(serviceInterface, ServiceValidator.TYPE_PUBLISHED);
		ServiceInterface svcInterface = serviceInterface.getAnnotation(ServiceInterface.class);
		SPFServiceDescriptor svcDesc = ServiceInterface.Convert.toServiceDescriptor(svcInterface);
		String token = getAccessToken();

		try {
			SPFError error = new SPFError();
			getService().unregisterService(token, svcDesc, error);
			if (!error.isOk()) {
				handleError(error);
			}
		} catch (RemoteException e) {
			catchRemoteException(e);
		}
	}

