private void checkAdapter() {
        PagerAdapter adapter = mPager.getAdapter();
        if (mAdapter != adapter) {
            if (mAdapter != null) {
                mAdapter.unregisterDataSetObserver(mObserver);
            }
            mAdapter = adapter;
