static boolean isNameChar(final int codePoint) {
		return
			isNameStartChar(codePoint)                   ||
			(codePoint == '-')                           ||
			(codePoint == '.')                           ||
			(codePoint >= '0' && codePoint <= '9')       ||
			(codePoint == 0xB7)                          ||
			(codePoint >= 0x0300 && codePoint <= 0x036F) ||
			(codePoint >= 0x203F && codePoint <= 0x2040);
	}

